const form=document.querySelector("#form");const campoTarefa=document.querySelector("#campo-tarefa");const conteudoPrincipal=document.querySelector("#conteudo-principal");const listaTarefas=document.querySelector("#lista-tarefas");const template=document.querySelector("#template");const fundoModal=document.querySelector("#fundo-modal");const modal=document.querySelector("#modal");const txtModal=document.querySelector("#txt-modal");const botaoFecharModal=document.querySelector("#botao-fechar-modal");const anoAtual=document.querySelector("#ano-atual");const alternarModal=(msg)=>{[fundoModal,modal].forEach((elModal)=>elModal.classList.toggle("esconder"));msg!==""?(txtModal.textContent=msg):setTimeout(()=>(txtModal.textContent=msg),300)};const limparCampoTarefa=()=>{campoTarefa.value="";window.innerWidth>=992?campoTarefa.focus():campoTarefa.blur()};const adicionarTarefa=(tarefa)=>{const cloneTemplate=template.content.cloneNode(!0);const itemListaTarefas=cloneTemplate.querySelector(".item-lista-tarefas");const txtTarefa=itemListaTarefas.querySelector(".txt-tarefa");txtTarefa.textContent=tarefa;listaTarefas.appendChild(itemListaTarefas);if(conteudoPrincipal.classList.contains("esconder"))
conteudoPrincipal.classList.remove("esconder");};const alternarEstadoTarefa=(botaoAlternarEstado)=>{const itemListaTarefas=botaoAlternarEstado.closest(".item-lista-tarefas");itemListaTarefas.classList.toggle("concluida");itemListaTarefas.classList.contains("concluida")?(botaoAlternarEstado.textContent="Tornar Pendente"):(botaoAlternarEstado.textContent="Concluir")};const deletarTarefa=(botaoDeletar)=>{botaoDeletar.closest(".item-lista-tarefas").remove();if(listaTarefas.children.length===0)
conteudoPrincipal.classList.add("esconder");alternarModal("Tarefa deletada com sucesso!")};document.addEventListener("DOMContentLoaded",()=>{const dataAtual=new Date();anoAtual.textContent=dataAtual.getFullYear()});form.addEventListener("submit",(e)=>{e.preventDefault();const tarefa=campoTarefa.value.trim();if(tarefa===""||tarefa.length>30){alternarModal("Erro: A tarefa é obrigatória e deve conter até 30 caracteres. Por favor, tente novamente.");limparCampoTarefa();return}
adicionarTarefa(tarefa);limparCampoTarefa();alternarModal("Tarefa adicionada com sucesso!")});listaTarefas.addEventListener("click",(e)=>{const elAlvo=e.target;if(elAlvo.classList.contains("botao-alternar-estado"))
alternarEstadoTarefa(elAlvo);if(elAlvo.classList.contains("botao-deletar"))deletarTarefa(elAlvo);});[fundoModal,botaoFecharModal].forEach((elModal)=>elModal.addEventListener("click",()=>alternarModal("")))